import{_ as s,o as n,c as a,a as t}from"./chunks/framework.8tiMeCK-.js";const u=JSON.parse('{"title":"Chapter 11: Deep into the Kernel: When the Debugger Becomes Part of the Kernel","description":"","frontmatter":{},"headers":[],"relativePath":"en/notes/linux_kernel_debugging/ch11_1.md","filePath":"en/notes/linux_kernel_debugging/ch11_1.md","lastUpdated":null}'),i={name:"en/notes/linux_kernel_debugging/ch11_1.md"};function o(l,e,r,p,h,d){return n(),a("div",null,[...e[0]||(e[0]=[t(`<h1 id="chapter-11-deep-into-the-kernel-when-the-debugger-becomes-part-of-the-kernel" tabindex="-1">Chapter 11: Deep into the Kernel: When the Debugger Becomes Part of the Kernel <a class="header-anchor" href="#chapter-11-deep-into-the-kernel-when-the-debugger-becomes-part-of-the-kernel" aria-label="Permalink to &quot;Chapter 11: Deep into the Kernel: When the Debugger Becomes Part of the Kernel&quot;">​</a></h1><p>There is a class of problems that ordinary debuggers simply cannot reach.</p><p>When your code runs at Ring 0, when the output buffer of <code>printk</code> cannot be flushed because of a system crash, or when you need to debug an Interrupt Handler—ordinary user-space debugging tools are not just powerless, they don&#39;t even exist.</p><p>Our mission in this chapter is to build a more low-level debugging capability. Instead of observing processes from the outside, we will make the debugger itself part of the kernel.</p><p>This is not as simple as &quot;learning to use a tool.&quot; Understanding KGDB means you begin to grasp the OS&#39;s god-mode perspective—the ability to pause the entire world, inspect its state, and then let time resume.</p><hr><h2 id="_11-1-technical-preparation" tabindex="-1">11.1 Technical Preparation <a class="header-anchor" href="#_11-1-technical-preparation" aria-label="Permalink to &quot;11.1 Technical Preparation&quot;">​</a></h2><p>Before diving into the kernel, we need to clear the ground first.</p><p>The base workspace and toolchain for this chapter still follow the conventions we established in Chapter 1—if you haven&#39;t set up that environment yet, now is a good time to go back and catch up. All code examples are already sitting in the book&#39;s GitHub repository, ready to be used whenever you need them.</p><p>But this time, we&#39;re playing with something a bit bigger. Besides our regular arsenal, we need to install heavier emulator components and a prepared rootfs image.</p><p>This step might be tedious, but don&#39;t cut corners. If the foundation isn&#39;t solid, once the kernel crashes later on, you won&#39;t even be able to tell which ring the problem occurred in.</p><h3 id="_1-installing-qemu-and-dependencies" tabindex="-1">1. Installing QEMU and Dependencies <a class="header-anchor" href="#_1-installing-qemu-and-dependencies" aria-label="Permalink to &quot;1. Installing QEMU and Dependencies&quot;">​</a></h3><p>We need the ARM and x86 versions of QEMU. This isn&#39;t just about running two virtual machines—in this chapter, we will rely heavily on QEMU&#39;s debugging features.</p><p>Open a terminal and run the following command. This string of packages will consume roughly 400 MB of disk space:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qemu-system-arm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qemu-system-x86</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lzop</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">libncursesw5 </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">libncursesw5-dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> p7zip-full</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Here&#39;s a breakdown of the key players:</p><ul><li><code>qemu-system-arm</code> and <code>qemu-system-x86</code>: These are our &quot;sandbox.&quot; KGDB debugging typically requires two machines, or a VM acting as the target. QEMU perfectly plays the role of this unfortunate target machine, and its GDB support is excellent.</li><li><code>lzop</code>: A compression tool. In the kernel world, you will sometimes encounter things in <code>xz</code> format.</li><li><code>libncursesw5</code>: If you want to configure the kernel (<code>make menuconfig</code>), this library is required for the menu interface to appear.</li><li><code>p7zip-full</code>: We&#39;ll need this to extract the rootfs later. Don&#39;t ask why we don&#39;t use <code>tar</code>—some things are just the way they are.</li></ul><h3 id="_2-getting-the-rootfs-image" tabindex="-1">2. Getting the Rootfs Image <a class="header-anchor" href="#_2-getting-the-rootfs-image" aria-label="Permalink to &quot;2. Getting the Rootfs Image&quot;">​</a></h3><p>Next, we need a ready-made ARM Linux rootfs.</p><p>We will use this file later when debugging kernel modules. Navigate to the <code>rootfs</code> directory of the book&#39;s source code, and download this hefty file (about 178 MB—grab a coffee and wait):</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">book_sr</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/ch11</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wget</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/PacktPublishing/Linux-Kernel-Debugging/raw/main/ch11/rootfs_deb.img.7z</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><blockquote><p><strong>warning</strong> <strong>Note — Watch out for this little pitfall</strong></p><p>If you run the <code>make</code> command above directly, GitHub might throw a little tantrum. Since the repository already contains a placeholder <code>rootfs.cpio.gz</code> (a meta file), <code>make</code> will rename the actual file you just downloaded to <code>rootfs.cpio.gz.tmp</code> to avoid overwriting it.</p><p>This name is wrong, and subsequent scripts won&#39;t be able to find it. You need to manually fix this &quot;typo&quot;:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></blockquote><p>rm rootfs_deb.img.7z mv rootfs_deb.img.7z.1 rootfs_deb.img.7z</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span>
<span class="line"><span>The directory structure should now be clean and tidy (if you&#39;re curious, you can flip ahead to Figure 11.8 to see what it ultimately looks like, but for now, let&#39;s just leave the file here and extract it when we need it later).</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 3. Prerequisite Knowledge About GDB</span></span>
<span class="line"><span></span></span>
<span class="line"><span>One last thing: we will use GDB extensively in this chapter.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>I&#39;ll assume you&#39;re no longer a GDB novice—for instance, you know what \`break\`, \`continue\`, \`step\`, and \`next\` do. If \`printf\` debugging is the only technique in your mental toolkit right now, I recommend searching for a &quot;GDB cheat sheet&quot; and giving it a quick glance.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>But don&#39;t worry—kernel debugging and user-space debugging are still a bit different. We will walk you through those truly cool (and dangerous) operations step by step.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>The ground is cleared. Next, we are going to officially implant this debugger cheat code into the kernel.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div>`,24)])])}const g=s(i,[["render",o]]);export{u as __pageData,g as default};
